-- Tier rules for VIP/Gold/Silver tier system
create table public.tier_rules (
  id uuid primary key default uuid_generate_v4(),
  program_id uuid references loyalty_programs(id) on delete cascade not null,
  tier text not null check (tier in ('silver', 'gold', 'vip')),
  min_transactions int not null,
  min_points numeric(10,2) default 0,
  created_at timestamptz default now(),
  unique(program_id, tier)
);

create index idx_tier_rules_program on public.tier_rules(program_id);

alter table public.tier_rules enable row level security;

create policy "Tier rules: merchant owner" on public.tier_rules
  for all using (program_id in (
    select id from loyalty_programs where merchant_id in (
      select id from merchants where user_id = auth.uid()
    )
  ));

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
    let updated = 0;

    // Get all customer cards with their programs
    const { data: cards } = await supabase
      .from('customer_cards')
      .select('id, customer_id, current_points, tier, program_id, customers(push_token)');

    for (const card of cards ?? []) {
      // Count transactions in last 90 days
      const { count: txCount } = await supabase
        .from('transactions')
        .select('id', { count: 'exact', head: true })
        .eq('card_id', card.id)
        .gte('created_at', ninetyDaysAgo);

      // Get tier rules for this program, ordered by min_transactions desc (highest tier first)
      const { data: rules } = await supabase
        .from('tier_rules')
        .select('*')
        .eq('program_id', card.program_id)
        .order('min_transactions', { ascending: false });

      if (!rules || rules.length === 0) continue;

      // Determine highest qualifying tier
      let newTier = 'bronze';
      for (const rule of rules) {
        if ((txCount ?? 0) >= rule.min_transactions && card.current_points >= (rule.min_points ?? 0)) {
          newTier = rule.tier;
          break; // rules sorted desc, first match is highest tier
        }
      }

      if (newTier !== card.tier) {
        await supabase.from('customer_cards').update({ tier: newTier }).eq('id', card.id);

        // Send notification on tier change
        const token = (card as any).customers?.push_token;
        if (token) {
          const tierOrder = ['bronze', 'silver', 'gold', 'vip'];
          const isUpgrade = tierOrder.indexOf(newTier) > tierOrder.indexOf(card.tier ?? 'bronze');
          const title = isUpgrade
            ? `Congratulations! You're now ${newTier.toUpperCase()}!`
            : `Tier updated to ${newTier.toUpperCase()}`;
          const body = isUpgrade
            ? 'Keep it up to unlock more rewards!'
            : 'Keep visiting to maintain your tier!';

          await fetch('https://exp.host/--/api/v2/push/send', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ to: token, title, body }),
          });

          await supabase.from('notifications').insert({
            customer_id: card.customer_id,
            title,
            body,
            type: 'reward_available',
            sent_at: new Date().toISOString(),
          });
        }
        updated++;
      }
    }

    return new Response(JSON.stringify({ updated }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});

