import { View, Text, StyleSheet } from 'react-native';
import type { CardWithProgram } from '../hooks/useCards';

const tierColors: Record<string, { bg: string; text: string }> = {
  bronze: { bg: '#a1887f', text: '#fff' },
  silver: { bg: '#b0bec5', text: '#fff' },
  gold: { bg: '#ffd54f', text: '#333' },
  vip: { bg: '#7c3aed', text: '#fff' },
};

export function CardItem({ card }: { card: CardWithProgram }) {
  const program = card.loyalty_programs;
  const merchant = program.merchants;
  const tier = card.tier ?? 'bronze';
  const colors = tierColors[tier] ?? tierColors.bronze;

  return (
    <View style={styles.card}>
      <View style={styles.header}>
        <View>
          <Text style={styles.merchant}>{merchant.name}</Text>
          <Text style={styles.program}>{program.name}</Text>
        </View>
        <View style={[styles.tierBadge, { backgroundColor: colors.bg }]}>
          <Text style={[styles.tierText, { color: colors.text }]}>
            {tier.toUpperCase()}
          </Text>
        </View>
      </View>
      {program.type === 'stamp' ? (
        <View style={styles.stampRow}>
          {Array.from({ length: program.stamp_goal || 10 }).map((_, i) => (
            <View key={i} style={[styles.stamp, i < card.current_stamps && styles.stampFilled]} />
          ))}
        </View>
      ) : (
        <Text style={styles.points}>{card.current_points} pts</Text>
      )}
      {program.reward_description && <Text style={styles.reward}>{program.reward_description}</Text>}
    </View>
  );
}

const styles = StyleSheet.create({
  card: { backgroundColor: '#fff', borderRadius: 16, padding: 20, marginBottom: 12, shadowColor: '#000', shadowOpacity: 0.05, shadowRadius: 10, elevation: 2 },
  header: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 },
  merchant: { fontSize: 14, color: '#666', marginBottom: 2 },
  program: { fontSize: 18, fontWeight: '700' },
  tierBadge: { paddingHorizontal: 10, paddingVertical: 4, borderRadius: 12 },
  tierText: { fontSize: 11, fontWeight: '800', letterSpacing: 0.5 },
  stampRow: { flexDirection: 'row', flexWrap: 'wrap', gap: 8 },
  stamp: { width: 28, height: 28, borderRadius: 14, borderWidth: 2, borderColor: '#ddd' },
  stampFilled: { backgroundColor: '#6366f1', borderColor: '#6366f1' },
  points: { fontSize: 32, fontWeight: '800', color: '#6366f1' },
  reward: { fontSize: 13, color: '#888', marginTop: 8 },
});

'use client';
import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

interface TierRule {
  tier: string;
  min_transactions: string;
  min_points: string;
}

const TIERS = ['silver', 'gold', 'vip'] as const;

const TIER_LABELS: Record<string, string> = {
  silver: 'Silver',
  gold: 'Gold',
  vip: 'VIP',
};

const TIER_COLORS: Record<string, string> = {
  silver: 'bg-gray-100 text-gray-700 border-gray-300',
  gold: 'bg-yellow-50 text-yellow-800 border-yellow-300',
  vip: 'bg-purple-50 text-purple-800 border-purple-300',
};

interface Props {
  programId: string;
}

export function TierRulesForm({ programId }: Props) {
  const supabase = createClient();
  const [rules, setRules] = useState<TierRule[]>(
    TIERS.map((tier) => ({ tier, min_transactions: '', min_points: '0' }))
  );
  const [loading, setLoading] = useState(false);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('tier_rules')
        .select('*')
        .eq('program_id', programId);

      if (data && data.length > 0) {
        setRules(
          TIERS.map((tier) => {
            const existing = data.find((r: any) => r.tier === tier);
            return {
              tier,
              min_transactions: existing ? String(existing.min_transactions) : '',
              min_points: existing ? String(existing.min_points ?? 0) : '0',
            };
          })
        );
      }
    }
    load();
  }, [programId]);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setSaved(false);

    // Delete existing rules for this program
    await supabase.from('tier_rules').delete().eq('program_id', programId);

    // Insert only tiers that have min_transactions defined
    const toInsert = rules
      .filter((r) => r.min_transactions !== '' && parseInt(r.min_transactions) > 0)
      .map((r) => ({
        program_id: programId,
        tier: r.tier,
        min_transactions: parseInt(r.min_transactions),
        min_points: parseFloat(r.min_points) || 0,
      }));

    if (toInsert.length > 0) {
      await supabase.from('tier_rules').insert(toInsert);
    }

    setLoading(false);
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  }

  function updateRule(tier: string, field: 'min_transactions' | 'min_points', value: string) {
    setRules((prev) =>
      prev.map((r) => (r.tier === tier ? { ...r, [field]: value } : r))
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4 max-w-lg mt-8">
      <div>
        <h3 className="text-lg font-semibold mb-1">Tier Rules</h3>
        <p className="text-sm text-gray-500 mb-4">
          Define the requirements for each loyalty tier. Customers are
          automatically promoted or demoted based on their activity in the last
          90 days. Leave a tier empty to disable it.
        </p>
      </div>

      {TIERS.map((tier) => {
        const rule = rules.find((r) => r.tier === tier)!;
        return (
          <div
            key={tier}
            className={`p-4 border rounded-lg ${TIER_COLORS[tier]}`}
          >
            <Label className="text-sm font-bold mb-2 block">
              {TIER_LABELS[tier]} Tier
            </Label>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label className="text-xs">Min. Transactions (90 days)</Label>
                <Input
                  type="number"
                  min="0"
                  value={rule.min_transactions}
                  onChange={(e) =>
                    updateRule(tier, 'min_transactions', e.target.value)
                  }
                  placeholder="e.g. 5"
                  className="bg-white"
                />
              </div>
              <div>
                <Label className="text-xs">Min. Points</Label>
                <Input
                  type="number"
                  min="0"
                  step="0.01"
                  value={rule.min_points}
                  onChange={(e) =>
                    updateRule(tier, 'min_points', e.target.value)
                  }
                  placeholder="0"
                  className="bg-white"
                />
              </div>
            </div>
          </div>
        );
      })}

      <div className="flex items-center gap-3">
        <Button type="submit" disabled={loading}>
          {loading ? 'Saving...' : 'Save Tier Rules'}
        </Button>
        {saved && (
          <span className="text-sm text-green-600 font-medium">
            Tier rules saved!
          </span>
        )}
      </div>
    </form>
  );
}

